import{_ as p,C as c,o as s,c as d,a2 as a,b as o,w as t,a as l,E as r,a3 as i}from"./chunks/framework.B72_uj9U.js";const C=JSON.parse('{"title":"CI/CD Integration","description":"","frontmatter":{"title":"CI/CD Integration","status":"complete"},"headers":[],"relativePath":"research/concepts/testing-and-verification/ci-cd-integration.md","filePath":"research/concepts/testing-and-verification/ci-cd-integration.md"}'),u={name:"research/concepts/testing-and-verification/ci-cd-integration.md"};function g(h,e,y,m,A,f){const n=c("Mermaid");return s(),d("div",null,[e[7]||(e[7]=a('<h1 id="ci-cd-integration" tabindex="-1">CI/CD Integration <a class="header-anchor" href="#ci-cd-integration" aria-label="Permalink to &quot;CI/CD Integration&quot;">​</a></h1><blockquote><p>How coding agents participate in continuous integration and delivery pipelines—creating pull requests, diagnosing CI failures, triaging issues, and operating autonomously in automated workflows without human interaction.</p></blockquote><hr><h2 id="why-ci-cd-integration-matters" tabindex="-1">Why CI/CD Integration Matters <a class="header-anchor" href="#why-ci-cd-integration-matters" aria-label="Permalink to &quot;Why CI/CD Integration Matters&quot;">​</a></h2><p>Coding agents are no longer confined to the interactive terminal session. The most impactful shift in agent design over the past year is the move from <strong>developer tool</strong> to <strong>development pipeline participant</strong>. An agent that can only write code when a human is watching is fundamentally limited; an agent that can respond to CI failures at 3 AM, triage incoming issues, review pull requests, and push fixes autonomously is a qualitatively different tool.</p><p>CI/CD integration enables agents to:</p><ul><li><strong>Create pull requests</strong> from issue descriptions or feature requests</li><li><strong>Respond to CI failures</strong> by analyzing logs, diagnosing root causes, and pushing fixes</li><li><strong>Perform automated code review</strong> with inline comments and suggestions</li><li><strong>Triage issues</strong> with labeling, prioritization, and initial analysis</li><li><strong>Run scheduled maintenance</strong> tasks on cron triggers</li><li><strong>Operate in event-driven pipelines</strong> triggered by webhooks, comments, or pushes</li></ul>',7)),(s(),o(i,null,{default:t(()=>[r(n,{id:"mermaid-50",class:"mermaid",graph:"flowchart%20LR%0A%20%20subgraph%20trad%5B%22Traditional%20Agent%20Workflow%22%5D%0A%20%20%20%20H%5B%22Human%22%5D%20--%3E%20AG1%5B%22Agent%22%5D%0A%20%20%20%20AG1%20--%3E%20TO%5B%22Terminal%20Output%22%5D%0A%20%20%20%20H%20--%3E%20HR%5B%22Human%20reviews%20locally%22%5D%0A%20%20end%0A%20%20subgraph%20cicd%5B%22CI%2FCD-Integrated%20Agent%20Workflow%22%5D%0A%20%20%20%20EV%5B%22Event%22%5D%20--%3E%20AG2%5B%22Agent%22%5D%0A%20%20%20%20AG2%20--%3E%20PR%5B%22PR%2FFix%22%5D%0A%20%20%20%20PR%20--%3E%20CI%5B%22CI%20Pipeline%22%5D%0A%20%20%20%20CI%20--%3E%20PF%5B%22Pass%2FFail%22%5D%0A%20%20%20%20CI%20--%3E%20WH%5B%22Webhook%22%5D%0A%20%20%20%20PF%20--%3E%20WH%0A%20%20%20%20WH%20--%3E%20EV%0A%20%20%20%20WH%20-.%20%22autonomous%20loop%22%20.-%3E%20EV%0A%20%20end%0A"})]),fallback:t(()=>[...e[0]||(e[0]=[l(" Loading... ",-1)])]),_:1})),e[8]||(e[8]=a(`<p>The <strong>autonomous loop</strong> is the key architectural difference. In a CI/CD context, the agent must handle the full cycle without a human in the loop: receive trigger → understand context → execute changes → verify via CI → iterate if needed. This requires robust <a href="#headlessnon-interactive-modes">non-interactive modes</a>, structured output, and reliable error handling.</p><hr><h2 id="github-actions-integration" tabindex="-1">GitHub Actions Integration <a class="header-anchor" href="#github-actions-integration" aria-label="Permalink to &quot;GitHub Actions Integration&quot;">​</a></h2><p>GitHub Actions is the dominant platform for agent-driven CI/CD workflows. Several agents ship first-party GitHub Actions that wrap their CLI tools for use in automated pipelines.</p><h3 id="claude-code-claude-code-action" tabindex="-1">Claude Code: claude-code-action <a class="header-anchor" href="#claude-code-claude-code-action" aria-label="Permalink to &quot;Claude Code: claude-code-action&quot;">​</a></h3><p>The <code>anthropics/claude-code-action</code> action is a <strong>general-purpose GitHub Action</strong> that enables Claude Code to participate in PR reviews, issue triage, and code implementation directly from GitHub events.</p><p><strong>Key capabilities:</strong></p><ul><li>Responds to <code>@claude</code> mentions in PR comments and issue threads</li><li>Performs automated code review with inline diff comments</li><li>Implements changes requested in issues and creates PRs</li><li>Supports Anthropic API, AWS Bedrock, and Google Vertex AI backends</li><li>Uses <code>/install-github-app</code> for streamlined repository setup</li></ul><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># .github/workflows/claude-code.yml</span></span>
<span class="line"><span style="color:#89B4FA;">name</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> Claude Code Agent</span></span>
<span class="line"><span style="color:#FAB387;">on</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">  issue_comment</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">    types</span><span style="color:#94E2D5;">:</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">created</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#89B4FA;">  pull_request_review_comment</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">    types</span><span style="color:#94E2D5;">:</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">created</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#89B4FA;">  issues</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">    types</span><span style="color:#94E2D5;">:</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">opened</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> labeled</span><span style="color:#9399B2;">]</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89B4FA;">jobs</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">  claude</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">    if</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> |</span></span>
<span class="line"><span style="color:#A6E3A1;">      (github.event_name == &#39;issue_comment&#39; &amp;&amp; contains(github.event.comment.body, &#39;@claude&#39;)) ||</span></span>
<span class="line"><span style="color:#A6E3A1;">      (github.event_name == &#39;pull_request_review_comment&#39; &amp;&amp; contains(github.event.comment.body, &#39;@claude&#39;)) ||</span></span>
<span class="line"><span style="color:#A6E3A1;">      (github.event_name == &#39;issues&#39; &amp;&amp; contains(github.event.issue.labels.*.name, &#39;claude&#39;))</span></span>
<span class="line"><span style="color:#89B4FA;">    runs-on</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> ubuntu-latest</span></span>
<span class="line"><span style="color:#89B4FA;">    permissions</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">      contents</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> write</span></span>
<span class="line"><span style="color:#89B4FA;">      pull-requests</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> write</span></span>
<span class="line"><span style="color:#89B4FA;">      issues</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> write</span></span>
<span class="line"><span style="color:#89B4FA;">    steps</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#9399B2;">      -</span><span style="color:#89B4FA;"> uses</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> actions/checkout@v4</span></span>
<span class="line"><span style="color:#89B4FA;">        with</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">          fetch-depth</span><span style="color:#94E2D5;">:</span><span style="color:#FAB387;"> 1</span></span>
<span class="line"></span>
<span class="line"><span style="color:#9399B2;">      -</span><span style="color:#89B4FA;"> uses</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> anthropics/claude-code-action@v1</span></span>
<span class="line"><span style="color:#89B4FA;">        with</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">          anthropic_api_key</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> \${{ secrets.ANTHROPIC_API_KEY }}</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">          # Optional: use Bedrock instead</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">          # use_bedrock: &quot;true&quot;</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">          # aws_access_key_id: \${{ secrets.AWS_ACCESS_KEY }}</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">          # aws_secret_access_key: \${{ secrets.AWS_SECRET_KEY }}</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">          # aws_region: &quot;us-east-1&quot;</span></span></code></pre></div><p>The action&#39;s architecture is notable: it <strong>wraps the full Claude Code CLI</strong> in a container, meaning the agent has access to the same tool suite (file editing, bash execution, search) as in interactive mode. The key difference is the permission model—in CI, the agent runs with <code>--dangerously-skip-permissions</code> or equivalent bypass flags, since there is no human to approve tool calls.</p><h3 id="gemini-cli-gemini-cli-action" tabindex="-1">Gemini CLI: gemini-cli-action <a class="header-anchor" href="#gemini-cli-gemini-cli-action" aria-label="Permalink to &quot;Gemini CLI: gemini-cli-action&quot;">​</a></h3><p>Google&#39;s <code>google-github-actions/run-gemini-cli</code> action provides similar functionality for the Gemini CLI agent, with particular strength in <strong>PR review</strong> and <strong>issue triage</strong>.</p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># .github/workflows/gemini-review.yml</span></span>
<span class="line"><span style="color:#89B4FA;">name</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> Gemini CLI Review</span></span>
<span class="line"><span style="color:#FAB387;">on</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">  pull_request</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">    types</span><span style="color:#94E2D5;">:</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">opened</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> synchronize</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#89B4FA;">  issue_comment</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">    types</span><span style="color:#94E2D5;">:</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">created</span><span style="color:#9399B2;">]</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89B4FA;">jobs</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">  review</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">    if</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> |</span></span>
<span class="line"><span style="color:#A6E3A1;">      github.event_name == &#39;pull_request&#39; ||</span></span>
<span class="line"><span style="color:#A6E3A1;">      (github.event_name == &#39;issue_comment&#39; &amp;&amp; contains(github.event.comment.body, &#39;@gemini-cli&#39;))</span></span>
<span class="line"><span style="color:#89B4FA;">    runs-on</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> ubuntu-latest</span></span>
<span class="line"><span style="color:#89B4FA;">    permissions</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">      contents</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> read</span></span>
<span class="line"><span style="color:#89B4FA;">      pull-requests</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> write</span></span>
<span class="line"><span style="color:#89B4FA;">      issues</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> write</span></span>
<span class="line"><span style="color:#89B4FA;">    steps</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#9399B2;">      -</span><span style="color:#89B4FA;"> uses</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> actions/checkout@v4</span></span>
<span class="line"></span>
<span class="line"><span style="color:#9399B2;">      -</span><span style="color:#89B4FA;"> uses</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> google-github-actions/run-gemini-cli@main</span></span>
<span class="line"><span style="color:#89B4FA;">        with</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">          gemini_api_key</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> \${{ secrets.GEMINI_API_KEY }}</span></span>
<span class="line"><span style="color:#89B4FA;">          prompt</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> |</span></span>
<span class="line"><span style="color:#A6E3A1;">            Review this pull request for correctness, security issues,</span></span>
<span class="line"><span style="color:#A6E3A1;">            and adherence to project conventions. Provide inline comments</span></span>
<span class="line"><span style="color:#A6E3A1;">            on specific lines where improvements are needed.</span></span></code></pre></div><p>Gemini CLI&#39;s action supports <strong>custom workflow prompts</strong>, allowing teams to define domain-specific review criteria. The <code>--output-format json</code> flag enables structured output parsing for downstream pipeline steps.</p><h3 id="droid-first-class-ci-cd-citizen" tabindex="-1">Droid: First-Class CI/CD Citizen <a class="header-anchor" href="#droid-first-class-ci-cd-citizen" aria-label="Permalink to &quot;Droid: First-Class CI/CD Citizen&quot;">​</a></h3><p><a href="./../../agents/droid/">Droid</a> distinguishes itself by treating CI/CD as a <strong>primary design goal</strong> rather than an afterthought. Its <code>.droid.yaml</code> configuration file defines automated behaviors declaratively:</p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># .droid.yaml</span></span>
<span class="line"><span style="color:#89B4FA;">version</span><span style="color:#94E2D5;">:</span><span style="color:#FAB387;"> 1</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89B4FA;">auto_review</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">  enabled</span><span style="color:#94E2D5;">:</span><span style="color:#FAB387;"> true</span></span>
<span class="line"><span style="color:#89B4FA;">  trigger</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#9399B2;">    -</span><span style="color:#FAB387;"> on</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> pull_request</span></span>
<span class="line"><span style="color:#89B4FA;">      actions</span><span style="color:#94E2D5;">:</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">opened</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> synchronize</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#89B4FA;">  filter</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">    paths</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#9399B2;">      -</span><span style="color:#A6E3A1;"> &quot;src/**&quot;</span></span>
<span class="line"><span style="color:#9399B2;">      -</span><span style="color:#A6E3A1;"> &quot;!src/generated/**&quot;</span></span>
<span class="line"><span style="color:#89B4FA;">    labels</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">      exclude</span><span style="color:#94E2D5;">:</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;skip-review&quot;</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#89B4FA;">  review</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">    focus</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#9399B2;">      -</span><span style="color:#A6E3A1;"> correctness</span></span>
<span class="line"><span style="color:#9399B2;">      -</span><span style="color:#A6E3A1;"> security</span></span>
<span class="line"><span style="color:#9399B2;">      -</span><span style="color:#A6E3A1;"> performance</span></span>
<span class="line"><span style="color:#89B4FA;">    severity_threshold</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> warning</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89B4FA;">ci_repair</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">  enabled</span><span style="color:#94E2D5;">:</span><span style="color:#FAB387;"> true</span></span>
<span class="line"><span style="color:#89B4FA;">  trigger</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#9399B2;">    -</span><span style="color:#FAB387;"> on</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> check_suite</span></span>
<span class="line"><span style="color:#89B4FA;">      conclusion</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> failure</span></span>
<span class="line"><span style="color:#89B4FA;">  repair</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">    max_attempts</span><span style="color:#94E2D5;">:</span><span style="color:#FAB387;"> 3</span></span>
<span class="line"><span style="color:#89B4FA;">    auto_push</span><span style="color:#94E2D5;">:</span><span style="color:#FAB387;"> true</span></span>
<span class="line"><span style="color:#89B4FA;">    require_ci_pass</span><span style="color:#94E2D5;">:</span><span style="color:#FAB387;"> true</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89B4FA;">issue_triage</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">  enabled</span><span style="color:#94E2D5;">:</span><span style="color:#FAB387;"> true</span></span>
<span class="line"><span style="color:#89B4FA;">  trigger</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#9399B2;">    -</span><span style="color:#FAB387;"> on</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> issues</span></span>
<span class="line"><span style="color:#89B4FA;">      actions</span><span style="color:#94E2D5;">:</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">opened</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#89B4FA;">  triage</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">    auto_label</span><span style="color:#94E2D5;">:</span><span style="color:#FAB387;"> true</span></span>
<span class="line"><span style="color:#89B4FA;">    priority_assessment</span><span style="color:#94E2D5;">:</span><span style="color:#FAB387;"> true</span></span>
<span class="line"><span style="color:#89B4FA;">    assign_to_team</span><span style="color:#94E2D5;">:</span><span style="color:#FAB387;"> true</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89B4FA;">scheduled</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#9399B2;">  -</span><span style="color:#89B4FA;"> cron</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> &quot;0 9 * * 1&quot;</span></span>
<span class="line"><span style="color:#89B4FA;">    task</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> dependency_audit</span></span>
<span class="line"><span style="color:#9399B2;">  -</span><span style="color:#89B4FA;"> cron</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> &quot;0 0 * * *&quot;</span></span>
<span class="line"><span style="color:#89B4FA;">    task</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> stale_branch_cleanup</span></span></code></pre></div><p>Droid&#39;s <code>auto_review</code> loop follows a structured pipeline: <strong>trigger on PR open → filter by path and label conditions → analyze diff → generate review comments → optionally trigger CI repair</strong> if the review identifies issues. The <code>ci_repair</code> section enables Droid&#39;s most distinctive feature: <strong>automatic GitHub Actions failure diagnosis and repair</strong> (covered in <a href="#ci-failure-diagnosis-and-repair">CI Failure Diagnosis and Repair</a>).</p><h3 id="openhands-openhands-resolver" tabindex="-1">OpenHands: openhands-resolver <a class="header-anchor" href="#openhands-openhands-resolver" aria-label="Permalink to &quot;OpenHands: openhands-resolver&quot;">​</a></h3><p><a href="./../../agents/openhands/">OpenHands</a> provides <code>openhands-resolver</code>, a purpose-built tool for <strong>automated issue resolution</strong> in GitHub repositories:</p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># .github/workflows/openhands-resolver.yml</span></span>
<span class="line"><span style="color:#89B4FA;">name</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> OpenHands Issue Resolver</span></span>
<span class="line"><span style="color:#FAB387;">on</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">  issues</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">    types</span><span style="color:#94E2D5;">:</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">labeled</span><span style="color:#9399B2;">]</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89B4FA;">jobs</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">  resolve</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">    if</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> contains(github.event.issue.labels.*.name, &#39;openhands&#39;)</span></span>
<span class="line"><span style="color:#89B4FA;">    runs-on</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> ubuntu-latest</span></span>
<span class="line"><span style="color:#89B4FA;">    steps</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#9399B2;">      -</span><span style="color:#89B4FA;"> uses</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> actions/checkout@v4</span></span>
<span class="line"></span>
<span class="line"><span style="color:#9399B2;">      -</span><span style="color:#89B4FA;"> name</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> Run OpenHands Resolver</span></span>
<span class="line"><span style="color:#89B4FA;">        uses</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> all-hands-ai/openhands-resolver@main</span></span>
<span class="line"><span style="color:#89B4FA;">        with</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">          github_token</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> \${{ secrets.GITHUB_TOKEN }}</span></span>
<span class="line"><span style="color:#89B4FA;">          llm_api_key</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> \${{ secrets.LLM_API_KEY }}</span></span>
<span class="line"><span style="color:#89B4FA;">          llm_model</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> &quot;anthropic/claude-sonnet-4-20250514&quot;</span></span>
<span class="line"><span style="color:#89B4FA;">          max_iterations</span><span style="color:#94E2D5;">:</span><span style="color:#FAB387;"> 30</span></span></code></pre></div><p>The resolver operates by: reading the issue description → setting up a sandboxed workspace → running the full OpenHands agent loop → creating a PR with the proposed fix. It is designed for <strong>batch processing</strong>: multiple issues can be resolved in parallel by labeling them simultaneously.</p><hr><h2 id="headless-non-interactive-modes" tabindex="-1">Headless/Non-Interactive Modes <a class="header-anchor" href="#headless-non-interactive-modes" aria-label="Permalink to &quot;Headless/Non-Interactive Modes&quot;">​</a></h2><p>For CI/CD pipelines, agents <strong>must</strong> operate without human interaction. A prompt asking &quot;Should I proceed?&quot; in a GitHub Actions runner will hang indefinitely and eventually timeout. Every serious CI/CD-capable agent provides a non-interactive mode.</p>`,25)),(s(),o(i,null,{default:t(()=>[r(n,{id:"mermaid-138",class:"mermaid",graph:"flowchart%20LR%0A%20%20subgraph%20interactive%5B%22Interactive%20Mode%22%5D%0A%20%20%20%20Q1%5B%22Agent%3A%20'Edit%20foo.js%3F'%22%5D%20--%3E%20Y%5B%22Human%3A%20'Yes'%22%5D%0A%20%20%20%20Y%20--%3E%20AE%5B%22Agent%20edits%22%5D%0A%20%20%20%20AE%20--%3E%20Q2%5B%22Agent%3A%20'Also%20modify%20bar.js%3F'%22%5D%0A%20%20%20%20Q2%20--%3E%20N%5B%22Human%3A%20'No'%22%5D%0A%20%20end%0A%20%20subgraph%20noninteractive%5B%22Non-Interactive%20Mode%22%5D%0A%20%20%20%20RT%5B%22Agent%20receives%20task%22%5D%20--%3E%20ET%5B%22Executes%20all%20tools%20(permissions%20bypassed)%22%5D%0A%20%20%20%20ET%20--%3E%20RS%5B%22Returns%20structured%20output%20(JSON%2Fexit%20code)%22%5D%0A%20%20end%0A"})]),fallback:t(()=>[...e[1]||(e[1]=[l(" Loading... ",-1)])]),_:1})),e[9]||(e[9]=a(`<h3 id="agent-by-agent-non-interactive-support" tabindex="-1">Agent-by-Agent Non-Interactive Support <a class="header-anchor" href="#agent-by-agent-non-interactive-support" aria-label="Permalink to &quot;Agent-by-Agent Non-Interactive Support&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Agent</th><th>Flag/Mode</th><th>Behavior</th><th>Output Format</th></tr></thead><tbody><tr><td><a href="./../../agents/claude-code/">Claude Code</a></td><td><code>-p</code> flag</td><td>Full agentic loop, no permission prompts</td><td>Streaming text or JSON</td></tr><tr><td><a href="./../../agents/codex/">Codex</a></td><td><code>exec</code> mode / <code>exec-server</code></td><td>Non-interactive over JSON-RPC/WebSocket</td><td>Structured JSON</td></tr><tr><td><a href="./../../agents/forgecode/">ForgeCode</a></td><td>Non-Interactive Mode</td><td>Rewrites system prompt to prohibit clarification</td><td>Text</td></tr><tr><td><a href="./../../agents/gemini-cli/">Gemini CLI</a></td><td><code>-p</code> + <code>--output-format json</code></td><td>Non-interactive with structured output</td><td>JSON</td></tr><tr><td><a href="./../../agents/goose/">Goose</a></td><td>Recipe mode</td><td><code>RetryManager</code> handles failures automatically</td><td>Text/structured</td></tr><tr><td><a href="./../../agents/pi-coding-agent/">Pi Coding Agent</a></td><td>Print/JSON mode</td><td>CI pipeline output</td><td>JSON</td></tr><tr><td><a href="./../../agents/droid/">Droid</a></td><td>CI runner mode</td><td>Triggered by <code>.droid.yaml</code> events</td><td>Structured</td></tr><tr><td><a href="./../../agents/openhands/">OpenHands</a></td><td>Resolver mode</td><td>Headless issue resolution</td><td>PR + comments</td></tr><tr><td><a href="./../../agents/warp/">Warp</a></td><td>Plan execution</td><td>Runs plan steps with exit code observation</td><td>Text</td></tr></tbody></table><h3 id="implementation-approaches" tabindex="-1">Implementation Approaches <a class="header-anchor" href="#implementation-approaches" aria-label="Permalink to &quot;Implementation Approaches&quot;">​</a></h3><p><strong>Claude Code&#39;s <code>-p</code> flag</strong> is the canonical example. When active, it runs the full agentic loop (tool calls, file edits, bash execution) without pausing for confirmation. Combined with <code>--dangerously-skip-permissions</code>, it opts out of the <a href="./../tool-systems/permission-systems.html">permission system</a> entirely.</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Run Claude Code non-interactively in a CI pipeline</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">claude</span><span style="color:#A6E3A1;"> -p</span><span style="color:#A6E3A1;"> &quot;Fix the failing test in src/auth.test.ts&quot;</span><span style="color:#F5C2E7;"> \\</span></span>
<span class="line"><span style="color:#A6E3A1;">  --output-format</span><span style="color:#A6E3A1;"> json</span><span style="color:#F5C2E7;"> \\</span></span>
<span class="line"><span style="color:#A6E3A1;">  --dangerously-skip-permissions</span></span></code></pre></div><p><strong>Codex&#39;s <code>exec-server</code></strong> maintains a warm JSON-RPC/WebSocket process that handles multiple requests without cold-start overhead—suited for batch CI operations.</p><p><strong>ForgeCode&#39;s prompt rewriting</strong> takes an unusual approach: it rewrites the system prompt to prohibit clarification requests, a <strong>prompt-level guarantee</strong> that relies on model instruction-following rather than architectural enforcement.</p><hr><h2 id="pr-workflow-integration" tabindex="-1">PR Workflow Integration <a class="header-anchor" href="#pr-workflow-integration" aria-label="Permalink to &quot;PR Workflow Integration&quot;">​</a></h2><p>Pull requests are the <strong>natural interface</strong> between agents and human development workflows. They provide code review, CI verification, and a structured approval process that maps cleanly to agent capabilities.</p><h3 id="the-agent-driven-pr-lifecycle" tabindex="-1">The Agent-Driven PR Lifecycle <a class="header-anchor" href="#the-agent-driven-pr-lifecycle" aria-label="Permalink to &quot;The Agent-Driven PR Lifecycle&quot;">​</a></h3>`,11)),(s(),o(i,null,{default:t(()=>[r(n,{id:"mermaid-311",class:"mermaid",graph:"flowchart%20TD%0A%20%20T%5B%22Trigger%20(issue%2C%20event%2C%20mention)%22%5D%20--%3E%20A%5B%22Agent%20Creates%20PR%22%5D%0A%20%20A%20--%3E%20CI%5B%22CI%20Pipeline%20Runs%22%5D%0A%20%20CI%20--%3E%7Cpass%7C%20HR%5B%22Human%20Review%22%5D%0A%20%20CI%20--%3E%7Cfail%7C%20F%5B%22Fail%22%5D%0A%20%20HR%20--%3E%7Capprove%7C%20M%5B%22Merge%22%5D%0A%20%20F%20--%3E%20AD%5B%22Agent%20Diagnoses%20%26%20Fixes%22%5D%0A%20%20AD%20--%3E%7Cloops%20back%20to%20CI%7C%20CI%0A"})]),fallback:t(()=>[...e[2]||(e[2]=[l(" Loading... ",-1)])]),_:1})),e[10]||(e[10]=a(`<h3 id="automated-code-review" tabindex="-1">Automated Code Review <a class="header-anchor" href="#automated-code-review" aria-label="Permalink to &quot;Automated Code Review&quot;">​</a></h3><p>Agents perform code review by analyzing PR diffs and posting inline comments:</p><ul><li><strong>Droid&#39;s auto_review loop</strong>: Trigger on PR open → filter by path/label → analyze diff → generate review comments with severity levels → post as GitHub review → optionally trigger <code>ci_repair</code> if issues are found.</li><li><strong>Claude Code</strong>: Leverages the full agent toolset—checks out the branch, runs tests, reads related files for context, then posts a review. More heavyweight but contextually richer than diff-only analysis.</li><li><strong>Gemini CLI</strong>: Structured analysis with configurable review criteria (security, performance, style) specified in the workflow configuration.</li></ul><h3 id="pre-merge-verification" tabindex="-1">Pre-Merge Verification <a class="header-anchor" href="#pre-merge-verification" aria-label="Permalink to &quot;Pre-Merge Verification&quot;">​</a></h3><p>A powerful pattern enabled by CI/CD integration: <strong>run the agent as a pre-merge check</strong>.</p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Use agent as a required status check</span></span>
<span class="line"><span style="color:#89B4FA;">name</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> Agent Verification</span></span>
<span class="line"><span style="color:#FAB387;">on</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">  pull_request</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">    types</span><span style="color:#94E2D5;">:</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">opened</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> synchronize</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#89B4FA;">jobs</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">  verify</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">    runs-on</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> ubuntu-latest</span></span>
<span class="line"><span style="color:#89B4FA;">    steps</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#9399B2;">      -</span><span style="color:#89B4FA;"> uses</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> actions/checkout@v4</span></span>
<span class="line"><span style="color:#9399B2;">      -</span><span style="color:#89B4FA;"> name</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> Agent Review</span></span>
<span class="line"><span style="color:#89B4FA;">        run</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> |</span></span>
<span class="line"><span style="color:#A6E3A1;">          claude -p &quot;Review this PR for bugs, security issues, and \\</span></span>
<span class="line"><span style="color:#A6E3A1;">            breaking changes. Exit with code 1 if critical issues found.&quot; \\</span></span>
<span class="line"><span style="color:#A6E3A1;">            --output-format json &gt; review.json</span></span>
<span class="line"><span style="color:#A6E3A1;">          </span></span>
<span class="line"><span style="color:#A6E3A1;">          # Parse result and set check status</span></span>
<span class="line"><span style="color:#A6E3A1;">          if jq -e &#39;.has_critical_issues&#39; review.json; then</span></span>
<span class="line"><span style="color:#A6E3A1;">            echo &quot;::error::Agent found critical issues&quot;</span></span>
<span class="line"><span style="color:#A6E3A1;">            exit 1</span></span>
<span class="line"><span style="color:#A6E3A1;">          fi</span></span></code></pre></div><p>This makes the agent a <strong>required status check</strong> in branch protection rules, meaning agent approval is required alongside human review and CI passage before merging.</p><hr><h2 id="ci-failure-diagnosis-and-repair" tabindex="-1">CI Failure Diagnosis and Repair <a class="header-anchor" href="#ci-failure-diagnosis-and-repair" aria-label="Permalink to &quot;CI Failure Diagnosis and Repair&quot;">​</a></h2><p>One of the highest-value CI/CD integrations is <strong>automated failure diagnosis</strong>. When a CI pipeline fails, the agent can analyze logs, identify the root cause, and propose (or even push) a fix.</p><h3 id="the-ci-fix-loop" tabindex="-1">The CI-Fix Loop <a class="header-anchor" href="#the-ci-fix-loop" aria-label="Permalink to &quot;The CI-Fix Loop&quot;">​</a></h3>`,11)),(s(),o(i,null,{default:t(()=>[r(n,{id:"mermaid-355",class:"mermaid",graph:"flowchart%20TD%0A%20%20P%5B%22Push%22%5D%20--%3E%20CI1%5B%22CI%20Runs%22%5D%0A%20%20CI1%20--%3E%20FD%5B%22Failure%20Detected%22%5D%0A%20%20FD%20--%3E%20FL%5B%22Fetch%20CI%20Logs%20(stdout%2Fstderr%2C%20exit%20codes%2C%20test%20output)%22%5D%0A%20%20FL%20--%3E%20AA%5B%22Agent%20Analyzes%20(parse%20errors%2C%20match%20to%20code%2C%20identify%20fix)%22%5D%0A%20%20AA%20--%3E%20PF%5B%22Push%20Fix%20(commit%20to%20same%20branch)%22%5D%0A%20%20PF%20--%3E%20CI2%5B%22CI%20Runs%20Again%22%5D%0A%20%20CI2%20--%3E%7CPass%7C%20D%5B%22Done%22%5D%0A%20%20CI2%20--%3E%7CFail%7C%20LP%5B%22Loop%20(max%20N%20attempts)%22%5D%0A%20%20LP%20--%3E%20FL%0A"})]),fallback:t(()=>[...e[3]||(e[3]=[l(" Loading... ",-1)])]),_:1})),e[11]||(e[11]=a('<h3 id="droid-s-github-action-repair" tabindex="-1">Droid&#39;s github_action_repair <a class="header-anchor" href="#droid-s-github-action-repair" aria-label="Permalink to &quot;Droid&#39;s github_action_repair&quot;">​</a></h3><p><a href="./../../agents/droid/">Droid&#39;s</a> <code>ci_repair</code> feature is the most complete implementation of automated CI repair:</p><ol><li><strong>Trigger</strong>: GitHub check suite completes with <code>failure</code> conclusion</li><li><strong>Fetch</strong>: Download workflow run logs via GitHub API</li><li><strong>Analyze</strong>: Parse logs for error patterns, stack traces, test failures</li><li><strong>Diagnose</strong>: Map errors to source code locations</li><li><strong>Fix</strong>: Generate and apply code changes</li><li><strong>Push</strong>: Commit fix to the failing branch</li><li><strong>Verify</strong>: Wait for CI to re-run; retry up to <code>max_attempts</code> times</li></ol><p>The <code>max_attempts</code> configuration is critical—without a bound, the agent could enter an infinite fix-break loop. Droid defaults to 3 attempts before escalating to a human.</p><h3 id="warp-s-exit-code-observation" tabindex="-1">Warp&#39;s Exit Code Observation <a class="header-anchor" href="#warp-s-exit-code-observation" aria-label="Permalink to &quot;Warp&#39;s Exit Code Observation&quot;">​</a></h3><p><a href="./../../agents/warp/">Warp</a> takes a simpler approach: its execution plans include explicit test steps, and Warp observes exit codes to determine success or failure. When a step fails, Warp can re-plan with the failure information included in context. While not a full CI integration, this pattern is the building block for CI-aware behavior.</p><h3 id="common-failure-patterns" tabindex="-1">Common Failure Patterns <a class="header-anchor" href="#common-failure-patterns" aria-label="Permalink to &quot;Common Failure Patterns&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Failure Type</th><th>Detection Signal</th><th>Typical Agent Fix</th></tr></thead><tbody><tr><td>Compilation error</td><td>Non-zero exit code + error message</td><td>Fix syntax/type errors</td></tr><tr><td>Test failure</td><td>Test framework output (FAIL, ✗)</td><td>Update test or fix code</td></tr><tr><td>Lint violation</td><td>Linter output with file:line format</td><td>Apply auto-fix or manual fix</td></tr><tr><td>Dependency issue</td><td>Resolution/install errors</td><td>Update lockfile or versions</td></tr><tr><td>Timeout</td><td>CI timeout signal</td><td>Optimize slow tests or increase limits</td></tr><tr><td>Permission denied</td><td>Auth/access error messages</td><td>Fix configuration, not code</td></tr></tbody></table><hr><h2 id="automated-issue-resolution" tabindex="-1">Automated Issue Resolution <a class="header-anchor" href="#automated-issue-resolution" aria-label="Permalink to &quot;Automated Issue Resolution&quot;">​</a></h2><p>The most ambitious CI/CD integration pattern: <strong>agents that automatically resolve issues</strong>.</p><h3 id="openhands-resolver" tabindex="-1">OpenHands Resolver <a class="header-anchor" href="#openhands-resolver" aria-label="Permalink to &quot;OpenHands Resolver&quot;">​</a></h3><p><a href="./../../agents/openhands/">OpenHands</a> provides the most mature automated issue resolver. The workflow:</p><ol><li><strong>Issue labeled</strong> with <code>openhands</code> tag (or configured trigger label)</li><li><strong>Resolver spins up</strong> a sandboxed workspace with the repository</li><li><strong>Agent reads</strong> issue title, description, and comments for context</li><li><strong>Agent executes</strong> the full OpenHands loop: explore codebase → plan → edit → test</li><li><strong>Agent creates PR</strong> with the proposed fix, linking to the original issue</li><li><strong>CI runs</strong> on the PR; if it fails, the agent can iterate</li></ol><p>This is <strong>fully autonomous</strong>: no human touches the keyboard between issue creation and PR submission. The human&#39;s role shifts to <strong>review and approval</strong> rather than implementation.</p><h3 id="gemini-cli-issue-triage" tabindex="-1">Gemini CLI Issue Triage <a class="header-anchor" href="#gemini-cli-issue-triage" aria-label="Permalink to &quot;Gemini CLI Issue Triage&quot;">​</a></h3><p><a href="./../../agents/gemini-cli/">Gemini CLI</a> focuses on the <strong>triage</strong> side of issue management:</p><ul><li><strong>Automated labeling</strong>: Analyze issue content and apply appropriate labels</li><li><strong>Priority assessment</strong>: Estimate severity and urgency from description</li><li><strong>Duplicate detection</strong>: Compare against existing open issues</li><li><strong>Initial analysis</strong>: Post a comment with preliminary analysis and suggested approach</li></ul><p>This is lower-autonomy than OpenHands&#39; full resolution but provides value without the risk of autonomous code changes.</p><h3 id="claude-code-issue-response" tabindex="-1">Claude Code Issue Response <a class="header-anchor" href="#claude-code-issue-response" aria-label="Permalink to &quot;Claude Code Issue Response&quot;">​</a></h3><p><a href="./../../agents/claude-code/">Claude Code</a> can be triggered from issue comments via <code>claude-code-action</code>. When a user mentions <code>@claude</code> in an issue, the action:</p><ol><li>Reads the issue context (title, description, conversation)</li><li>Checks out the repository</li><li>Runs Claude Code with the issue as the prompt</li><li>Creates a PR or posts a comment with analysis</li></ol><hr><h2 id="status-checks-and-branch-protection" tabindex="-1">Status Checks and Branch Protection <a class="header-anchor" href="#status-checks-and-branch-protection" aria-label="Permalink to &quot;Status Checks and Branch Protection&quot;">​</a></h2><p>Agent-generated PRs must pass the <strong>same quality gates</strong> as human-generated ones. This is both a correctness concern and a security boundary.</p><h3 id="how-agents-interact-with-required-checks" tabindex="-1">How Agents Interact with Required Checks <a class="header-anchor" href="#how-agents-interact-with-required-checks" aria-label="Permalink to &quot;How Agents Interact with Required Checks&quot;">​</a></h3>',26)),(s(),o(i,null,{default:t(()=>[r(n,{id:"mermaid-611",class:"mermaid",graph:"flowchart%20TD%0A%20%20APR%5B%22Agent%20Creates%20PR%22%5D%20--%3E%20SC%0A%20%20APR%20--%3E%20RR%0A%20%20APR%20--%3E%20RS%0A%20%20APR%20--%3E%20RP%0A%20%20SC%5B%22%E2%98%91%20Require%20status%20checks%20to%20pass%22%5D%20--%3E%20UT%5B%22Unit%20tests%20%E2%9C%93%2F%E2%9C%97%22%5D%0A%20%20SC%20--%3E%20LT%5B%22Lint%20%E2%9C%93%2F%E2%9C%97%22%5D%0A%20%20SC%20--%3E%20TC%5B%22Type%20check%20%E2%9C%93%2F%E2%9C%97%22%5D%0A%20%20SC%20--%3E%20AR%5B%22Agent%20review%20%E2%9C%93%2F%E2%9C%97%20(optional)%22%5D%0A%20%20RR%5B%22%E2%98%91%20Require%20pull%20request%20reviews%22%5D%20--%3E%20HA%5B%22At%20least%201%20human%20approval%22%5D%0A%20%20RS%5B%22%E2%98%91%20Require%20signed%20commits%20(optional)%22%5D%20--%3E%20GPG%5B%22Agent%20must%20have%20GPG%20key%20configured%22%5D%0A%20%20RP%5B%22%E2%98%91%20Restrict%20who%20can%20push%22%5D%20--%3E%20BA%5B%22Agent's%20GitHub%20App%20or%20bot%20account%22%5D%0A"})]),fallback:t(()=>[...e[4]||(e[4]=[l(" Loading... ",-1)])]),_:1})),e[12]||(e[12]=a(`<p>Key design principle: <strong>agent-generated code is untrusted code</strong>. Even if an agent created a PR, human review should be required before merge. Branch protection rules enforce this by requiring at least one human approval regardless of how the PR was created.</p><h3 id="agent-as-status-check" tabindex="-1">Agent as Status Check <a class="header-anchor" href="#agent-as-status-check" aria-label="Permalink to &quot;Agent as Status Check&quot;">​</a></h3><p>Some teams add the agent itself as a <strong>required status check</strong>. This creates a two-layer review: the agent reviews human PRs, and humans review agent PRs. Both must pass before merge.</p><hr><h2 id="pipeline-automation-patterns" tabindex="-1">Pipeline Automation Patterns <a class="header-anchor" href="#pipeline-automation-patterns" aria-label="Permalink to &quot;Pipeline Automation Patterns&quot;">​</a></h2><p>Beyond PR workflows, agents integrate into broader automation patterns.</p><h3 id="event-driven-patterns" tabindex="-1">Event-Driven Patterns <a class="header-anchor" href="#event-driven-patterns" aria-label="Permalink to &quot;Event-Driven Patterns&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Trigger</th><th>Event</th><th>Agent Action</th><th>Example</th></tr></thead><tbody><tr><td>Push to branch</td><td><code>push</code></td><td>Run analysis, check for regressions</td><td>Lint new code</td></tr><tr><td>PR opened</td><td><code>pull_request</code></td><td>Full code review</td><td>Droid auto_review</td></tr><tr><td>PR comment</td><td><code>issue_comment</code></td><td>Respond to requests</td><td><code>@claude fix this</code></td></tr><tr><td>Issue opened</td><td><code>issues</code></td><td>Triage or resolve</td><td>OpenHands resolver</td></tr><tr><td>CI failure</td><td><code>check_suite</code></td><td>Diagnose and repair</td><td>Droid ci_repair</td></tr><tr><td>Scheduled</td><td><code>cron</code></td><td>Maintenance tasks</td><td>Dependency updates</td></tr><tr><td>Webhook</td><td>External event</td><td>Custom automation</td><td>Slack → agent → PR</td></tr></tbody></table><h3 id="scheduled-maintenance" tabindex="-1">Scheduled Maintenance <a class="header-anchor" href="#scheduled-maintenance" aria-label="Permalink to &quot;Scheduled Maintenance&quot;">​</a></h3><p><a href="./../../agents/droid/">Droid&#39;s</a> cron-triggered tasks demonstrate <strong>proactive agent behavior</strong>:</p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Droid scheduled maintenance</span></span>
<span class="line"><span style="color:#89B4FA;">scheduled</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#9399B2;">  -</span><span style="color:#89B4FA;"> cron</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> &quot;0 9 * * 1&quot;</span><span style="color:#6C7086;font-style:italic;">        # Every Monday at 9am</span></span>
<span class="line"><span style="color:#89B4FA;">    task</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> dependency_audit</span><span style="color:#6C7086;font-style:italic;">     # Check for outdated/vulnerable deps</span></span>
<span class="line"><span style="color:#9399B2;">  -</span><span style="color:#89B4FA;"> cron</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> &quot;0 0 * * *&quot;</span><span style="color:#6C7086;font-style:italic;">        # Every day at midnight</span></span>
<span class="line"><span style="color:#89B4FA;">    task</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> stale_branch_cleanup</span><span style="color:#6C7086;font-style:italic;"> # Remove merged/stale branches</span></span>
<span class="line"><span style="color:#9399B2;">  -</span><span style="color:#89B4FA;"> cron</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> &quot;0 6 * * 3&quot;</span><span style="color:#6C7086;font-style:italic;">        # Every Wednesday at 6am</span></span>
<span class="line"><span style="color:#89B4FA;">    task</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> code_quality_report</span><span style="color:#6C7086;font-style:italic;">  # Generate quality metrics</span></span></code></pre></div><h3 id="batch-operations" tabindex="-1">Batch Operations <a class="header-anchor" href="#batch-operations" aria-label="Permalink to &quot;Batch Operations&quot;">​</a></h3><p>Multiple issues can be resolved in parallel by labeling them simultaneously. OpenHands resolver supports this natively—each labeled issue spawns an independent agent instance. This enables <strong>throughput scaling</strong>: a team can label 10 issues and get 10 PRs.</p><h3 id="webhook-driven-workflows" tabindex="-1">Webhook-Driven Workflows <a class="header-anchor" href="#webhook-driven-workflows" aria-label="Permalink to &quot;Webhook-Driven Workflows&quot;">​</a></h3><p>Claude Code supports integration channels including Telegram, Discord, and custom webhooks. This enables patterns like:</p>`,15)),(s(),o(i,null,{default:t(()=>[r(n,{id:"mermaid-768",class:"mermaid",graph:"flowchart%20TD%0A%20%20SM%5B%22Slack%20message%3A%20'Can%20someone%20fix%20the%20auth%20timeout%20bug%3F'%22%5D%20--%3E%20WH%5B%22Webhook%22%5D%0A%20%20WH%20--%3E%20GA%5B%22GitHub%20Action%22%5D%0A%20%20GA%20--%3E%20CC%5B%22Claude%20Code%22%5D%0A%20%20CC%20--%3E%20PR%5B%22PR%20created%22%5D%0A%20%20PR%20--%3E%20SN%5B%22Slack%20notification%3A%20'PR%20%23142%20created%20to%20fix%20auth%20timeout'%22%5D%0A"})]),fallback:t(()=>[...e[5]||(e[5]=[l(" Loading... ",-1)])]),_:1})),e[13]||(e[13]=a('<hr><h2 id="security-considerations" tabindex="-1">Security Considerations <a class="header-anchor" href="#security-considerations" aria-label="Permalink to &quot;Security Considerations&quot;">​</a></h2><p>CI/CD integration introduces significant security surface area. An agent operating autonomously in a pipeline has access to secrets, can push code, and operates without real-time human oversight.</p><h3 id="api-key-management" tabindex="-1">API Key Management <a class="header-anchor" href="#api-key-management" aria-label="Permalink to &quot;API Key Management&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Concern</th><th>Best Practice</th><th>Risk if Violated</th></tr></thead><tbody><tr><td>API key storage</td><td>GitHub Secrets / vault</td><td>Key leakage in logs</td></tr><tr><td>Key rotation</td><td>Regular rotation schedule</td><td>Compromised long-lived keys</td></tr><tr><td>Key scoping</td><td>Minimum required permissions</td><td>Over-privileged agent</td></tr><tr><td>Audit logging</td><td>Log all API key usage</td><td>Undetected misuse</td></tr></tbody></table><h3 id="least-privilege-principle" tabindex="-1">Least-Privilege Principle <a class="header-anchor" href="#least-privilege-principle" aria-label="Permalink to &quot;Least-Privilege Principle&quot;">​</a></h3><p>Agents in CI/CD should operate with <strong>minimal permissions</strong>:</p><ul><li><strong>Repository access</strong>: Read + write to contents and PRs only</li><li><strong>No admin access</strong>: Agents should not manage repository settings</li><li><strong>Scoped tokens</strong>: Use fine-grained GitHub tokens, not classic PATs</li><li><strong>Time-limited</strong>: Tokens should expire; avoid permanent credentials</li></ul><h3 id="sandboxed-execution" tabindex="-1">Sandboxed Execution <a class="header-anchor" href="#sandboxed-execution" aria-label="Permalink to &quot;Sandboxed Execution&quot;">​</a></h3><p><a href="./../../agents/codex/">Codex</a> provides the strongest sandboxing model for CI/CD: all agent code execution occurs in an isolated sandbox with restricted network access and filesystem isolation. This prevents malicious code generated by the LLM from escaping the sandbox to compromise the CI environment.</p>',10)),(s(),o(i,null,{default:t(()=>[r(n,{id:"mermaid-874",class:"mermaid",graph:"flowchart%20TD%0A%20%20subgraph%20host%5B%22CI%20Runner%20(Host)%22%5D%0A%20%20%20%20subgraph%20sandbox%5B%22Agent%20Sandbox%22%5D%0A%20%20%20%20%20%20AP%5B%22Agent%20Process%22%5D%0A%20%20%20%20%20%20CE%5B%22Code%20Execution%22%5D%0A%20%20%20%20%20%20NN%5B%22No%20network%20access%22%5D%0A%20%20%20%20%20%20FI%5B%22Filesystem%20isolated%22%5D%0A%20%20%20%20end%0A%20%20%20%20SE%5B%22Secrets%20injected%20via%20env%20vars%20only%22%5D%0A%20%20end%0A"})]),fallback:t(()=>[...e[6]||(e[6]=[l(" Loading... ",-1)])]),_:1})),e[14]||(e[14]=a('<h3 id="commit-signing" tabindex="-1">Commit Signing <a class="header-anchor" href="#commit-signing" aria-label="Permalink to &quot;Commit Signing&quot;">​</a></h3><p>Agent-generated commits should be <strong>signed</strong> to maintain audit trails:</p><ul><li>GitHub Apps automatically sign commits with the app&#39;s identity</li><li>Bot accounts can be configured with GPG keys</li><li>Unsigned agent commits may fail branch protection rules that require signing</li><li>Signed commits provide <strong>non-repudiation</strong>: you can verify which agent made which change</li></ul><h3 id="pull-request-security" tabindex="-1">Pull Request Security <a class="header-anchor" href="#pull-request-security" aria-label="Permalink to &quot;Pull Request Security&quot;">​</a></h3><p>Agent-generated code is <strong>untrusted code</strong>. Critical guardrails:</p><ol><li><strong>Never auto-merge</strong> agent PRs without human review</li><li><strong>Run the full CI suite</strong> on agent PRs (same as human PRs)</li><li><strong>Review for prompt injection</strong> — adversarial issue descriptions could manipulate the agent</li><li><strong>Restrict file scope</strong> — agents should not modify CI configuration, secrets, or workflows</li><li><strong>Monitor for exfiltration</strong> — ensure the agent doesn&#39;t leak secrets through code changes</li></ol><hr><h2 id="cross-agent-ci-cd-capabilities" tabindex="-1">Cross-Agent CI/CD Capabilities <a class="header-anchor" href="#cross-agent-ci-cd-capabilities" aria-label="Permalink to &quot;Cross-Agent CI/CD Capabilities&quot;">​</a></h2><p>The following table summarizes CI/CD integration capabilities across all 17 agents studied in this research library.</p><table tabindex="0"><thead><tr><th>Agent</th><th style="text-align:center;">GitHub Action</th><th style="text-align:center;">Non-Interactive Mode</th><th style="text-align:center;">PR Review</th><th style="text-align:center;">CI Repair</th><th style="text-align:center;">Issue Resolution</th><th style="text-align:center;">Scheduled Tasks</th></tr></thead><tbody><tr><td><a href="./../../agents/aider/">Aider</a></td><td style="text-align:center;">—</td><td style="text-align:center;">✅ CLI flags</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td><a href="./../../agents/ante/">Ante</a></td><td style="text-align:center;">—</td><td style="text-align:center;">⚠️ Limited</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td><a href="./../../agents/capy/">Capy</a></td><td style="text-align:center;">—</td><td style="text-align:center;">⚠️ Limited</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td><a href="./../../agents/claude-code/">Claude Code</a></td><td style="text-align:center;">✅ anthropics/claude-code-action</td><td style="text-align:center;">✅ <code>-p</code> flag</td><td style="text-align:center;">✅ Inline</td><td style="text-align:center;">⚠️ Via action</td><td style="text-align:center;">✅ Via action</td><td style="text-align:center;">—</td></tr><tr><td><a href="./../../agents/codex/">Codex</a></td><td style="text-align:center;">—</td><td style="text-align:center;">✅ exec/exec-server</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td><a href="./../../agents/droid/">Droid</a></td><td style="text-align:center;">✅ Built-in</td><td style="text-align:center;">✅ .droid.yaml</td><td style="text-align:center;">✅ auto_review</td><td style="text-align:center;">✅ ci_repair</td><td style="text-align:center;">✅ Issue triage</td><td style="text-align:center;">✅ Cron</td></tr><tr><td><a href="./../../agents/forgecode/">ForgeCode</a></td><td style="text-align:center;">—</td><td style="text-align:center;">✅ Non-Interactive Mode</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td><a href="./../../agents/gemini-cli/">Gemini CLI</a></td><td style="text-align:center;">✅ google-github-actions/run-gemini-cli</td><td style="text-align:center;">✅ <code>-p</code> + <code>--output-format json</code></td><td style="text-align:center;">✅ PR review</td><td style="text-align:center;">—</td><td style="text-align:center;">✅ Issue triage</td><td style="text-align:center;">—</td></tr><tr><td><a href="./../../agents/goose/">Goose</a></td><td style="text-align:center;">—</td><td style="text-align:center;">✅ Recipe mode</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td><a href="./../../agents/junie-cli/">Junie CLI</a></td><td style="text-align:center;">—</td><td style="text-align:center;">⚠️ Limited</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td><a href="./../../agents/mini-swe-agent/">Mini SWE Agent</a></td><td style="text-align:center;">—</td><td style="text-align:center;">✅ Headless</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">✅ Issue-driven</td><td style="text-align:center;">—</td></tr><tr><td><a href="./../../agents/opencode/">OpenCode</a></td><td style="text-align:center;">—</td><td style="text-align:center;">⚠️ Limited</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td><a href="./../../agents/openhands/">OpenHands</a></td><td style="text-align:center;">✅ openhands-resolver</td><td style="text-align:center;">✅ Resolver mode</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">✅ Full resolver</td><td style="text-align:center;">—</td></tr><tr><td><a href="./../../agents/pi-coding-agent/">Pi Coding Agent</a></td><td style="text-align:center;">—</td><td style="text-align:center;">✅ Print/JSON mode</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">✅ Issue-driven</td><td style="text-align:center;">—</td></tr><tr><td><a href="./../../agents/sage-agent/">Sage Agent</a></td><td style="text-align:center;">—</td><td style="text-align:center;">✅ Headless</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">✅ Issue-driven</td><td style="text-align:center;">—</td></tr><tr><td><a href="./../../agents/tongagents/">TongAgents</a></td><td style="text-align:center;">—</td><td style="text-align:center;">⚠️ Limited</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td><a href="./../../agents/warp/">Warp</a></td><td style="text-align:center;">—</td><td style="text-align:center;">✅ Plan execution</td><td style="text-align:center;">—</td><td style="text-align:center;">⚠️ Exit code aware</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr></tbody></table><p><strong>Legend:</strong> ✅ = Full support | ⚠️ = Partial/limited | — = Not supported</p><h3 id="maturity-tiers" tabindex="-1">Maturity Tiers <a class="header-anchor" href="#maturity-tiers" aria-label="Permalink to &quot;Maturity Tiers&quot;">​</a></h3><p>The agents cluster into three tiers of CI/CD maturity:</p><p><strong>Tier 1 — Full CI/CD Citizens</strong> (Droid, Claude Code, Gemini CLI, OpenHands): First-party GitHub Actions, automated PR workflows, event-driven triggers, and structured non-interactive output. These agents are designed to operate as autonomous pipeline participants.</p><p><strong>Tier 2 — CI-Capable</strong> (Codex, ForgeCode, Goose, Pi Coding Agent, Aider, Warp, Mini SWE Agent, Sage Agent): Robust non-interactive modes that enable CI/CD integration via custom wrapper scripts. These agents can participate in pipelines but require more setup and orchestration.</p><p><strong>Tier 3 — Interactive-First</strong> (Ante, Capy, Junie CLI, OpenCode, TongAgents): Primarily designed for interactive use. CI/CD integration is possible but requires significant custom tooling and may lack structured output formats.</p><hr><h2 id="design-principles-for-ci-cd-integration" tabindex="-1">Design Principles for CI/CD Integration <a class="header-anchor" href="#design-principles-for-ci-cd-integration" aria-label="Permalink to &quot;Design Principles for CI/CD Integration&quot;">​</a></h2><p>Building on patterns observed across the 17 agents, several design principles emerge:</p><h3 id="_1-fail-loudly-not-silently" tabindex="-1">1. Fail Loudly, Not Silently <a class="header-anchor" href="#_1-fail-loudly-not-silently" aria-label="Permalink to &quot;1. Fail Loudly, Not Silently&quot;">​</a></h3><p>In CI/CD, a silent failure is worse than a loud one. Agents should:</p><ul><li>Exit with non-zero codes on failure</li><li>Produce structured error output parseable by CI systems</li><li>Never silently swallow exceptions in non-interactive mode</li></ul><h3 id="_2-bound-autonomous-behavior" tabindex="-1">2. Bound Autonomous Behavior <a class="header-anchor" href="#_2-bound-autonomous-behavior" aria-label="Permalink to &quot;2. Bound Autonomous Behavior&quot;">​</a></h3><p>Every autonomous loop needs bounds:</p><ul><li><strong>Max iterations</strong> for CI repair loops (Droid: 3 attempts)</li><li><strong>Max time</strong> for agent execution (prevent runaway costs)</li><li><strong>Max scope</strong> for changes (prevent agents from rewriting entire codebases)</li></ul><h3 id="_3-maintain-auditability" tabindex="-1">3. Maintain Auditability <a class="header-anchor" href="#_3-maintain-auditability" aria-label="Permalink to &quot;3. Maintain Auditability&quot;">​</a></h3><p>Every agent action in CI/CD should be traceable:</p><ul><li>Signed commits with agent identity</li><li>Structured logs with tool call traces</li><li>PR descriptions that explain agent reasoning</li><li>Links from PRs to triggering issues/events</li></ul><h3 id="_4-treat-agent-output-as-untrusted" tabindex="-1">4. Treat Agent Output as Untrusted <a class="header-anchor" href="#_4-treat-agent-output-as-untrusted" aria-label="Permalink to &quot;4. Treat Agent Output as Untrusted&quot;">​</a></h3><p>Agent-generated code, reviews, and suggestions should go through the same review process as human contributions. The pipeline should enforce this through branch protection rules, required reviews, and full CI suite execution.</p><h3 id="_5-support-graceful-degradation" tabindex="-1">5. Support Graceful Degradation <a class="header-anchor" href="#_5-support-graceful-degradation" aria-label="Permalink to &quot;5. Support Graceful Degradation&quot;">​</a></h3><p>When the LLM API is down, rate-limited, or returns errors, the CI pipeline should not break. Agent steps should be <strong>optional checks</strong> that degrade gracefully, not blocking gates that halt all development.</p><hr><h2 id="real-world-implementations" tabindex="-1">Real-World Implementations <a class="header-anchor" href="#real-world-implementations" aria-label="Permalink to &quot;Real-World Implementations&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Agent</th><th>CI/CD Source</th><th>Key File/Component</th><th>Notes</th></tr></thead><tbody><tr><td><a href="./../../agents/aider/">Aider</a></td><td>CLI flags</td><td><code>--yes</code>, <code>--no-git</code></td><td>Enables scripted execution</td></tr><tr><td><a href="./../../agents/ante/">Ante</a></td><td>—</td><td>—</td><td>Interactive-first design</td></tr><tr><td><a href="./../../agents/capy/">Capy</a></td><td>—</td><td>—</td><td>Interactive-first design</td></tr><tr><td><a href="./../../agents/claude-code/">Claude Code</a></td><td><code>anthropics/claude-code-action</code></td><td><code>-p</code>, <code>--dangerously-skip-permissions</code></td><td>Most widely adopted CI action</td></tr><tr><td><a href="./../../agents/codex/">Codex</a></td><td><code>exec</code> / <code>exec-server</code></td><td>JSON-RPC/WebSocket API</td><td>Server mode for batch CI</td></tr><tr><td><a href="./../../agents/droid/">Droid</a></td><td><code>.droid.yaml</code></td><td><code>auto_review</code>, <code>ci_repair</code></td><td>Most complete CI/CD native</td></tr><tr><td><a href="./../../agents/forgecode/">ForgeCode</a></td><td>Non-Interactive Mode</td><td>System prompt rewrite</td><td>Prompt-level guarantee</td></tr><tr><td><a href="./../../agents/gemini-cli/">Gemini CLI</a></td><td><code>google-github-actions/run-gemini-cli</code></td><td><code>-p</code>, <code>--output-format json</code></td><td>Strong triage capabilities</td></tr><tr><td><a href="./../../agents/goose/">Goose</a></td><td>Recipe mode</td><td><code>RetryManager</code></td><td>Automated retry on failure</td></tr><tr><td><a href="./../../agents/junie-cli/">Junie CLI</a></td><td>—</td><td>—</td><td>JetBrains ecosystem focus</td></tr><tr><td><a href="./../../agents/mini-swe-agent/">Mini SWE Agent</a></td><td>Headless execution</td><td>Issue-to-PR pipeline</td><td>Lightweight resolver</td></tr><tr><td><a href="./../../agents/opencode/">OpenCode</a></td><td>—</td><td>—</td><td>TUI-focused design</td></tr><tr><td><a href="./../../agents/openhands/">OpenHands</a></td><td><code>openhands-resolver</code></td><td>Sandboxed workspace</td><td>Full issue-to-PR automation</td></tr><tr><td><a href="./../../agents/pi-coding-agent/">Pi Coding Agent</a></td><td>Print/JSON mode</td><td>Structured output</td><td>Research-oriented agent</td></tr><tr><td><a href="./../../agents/sage-agent/">Sage Agent</a></td><td>Headless execution</td><td>Issue-to-PR pipeline</td><td>Multi-agent architecture</td></tr><tr><td><a href="./../../agents/tongagents/">TongAgents</a></td><td>—</td><td>—</td><td>Multi-agent research system</td></tr><tr><td><a href="./../../agents/warp/">Warp</a></td><td>Plan execution</td><td>Exit code observation</td><td>Foundation for CI awareness</td></tr></tbody></table><hr><p><em>This analysis covers CI/CD integration patterns as implemented in publicly available open-source coding agents as of mid-2025. GitHub Actions workflows, agent capabilities, and CI/CD features may change between versions.</em></p>',37))])}const E=p(u,[["render",g]]);export{C as __pageData,E as default};
